
.wb-status-bar {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 12px;
  font-size: 11px;
  color: var(--wb-text-muted);
  background: var(--wb-bg-panel);
  border-radius: 8px;
  min-height: 24px;
}

.wb-status-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--wb-text-muted);
  flex-shrink: 0;
}

.wb-status-dot.is-ok {
  background: var(--wb-success, #4EDEA3);
}

.wb-status-dot.is-modified {
  background: var(--wb-secondary, #FBBF24);
  animation: status-pulse 2s ease-in-out infinite;
}

@keyframes status-pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

.wb-status-text {
  font-weight: 500;
}

.wb-status-sep {
  opacity: 0.4;
}

.wb-status-meta {
  color: var(--wb-text-main);
}

.wb-status-meta-dim {
  opacity: 0.6;
}

.wb-status-spacer {
  flex: 1;
}
