
.wb-floating-window {
  position: fixed;
  max-width: calc(100vw - 16px);
  max-height: min(74vh, 760px);
  border-radius: 12px;
  background: var(--wb-surface-highest, var(--wb-bg-panel));
  box-shadow: var(--wb-shadow-main);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.wb-floating-header {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: center;
  padding: 12px 16px;
  border-bottom: 1px solid var(--wb-border-subtle);
  background: var(--wb-surface-high, var(--wb-bg-panel));
  cursor: move;
  user-select: none;
  touch-action: none;
}

.wb-floating-header strong {
  font-size: 12px;
  color: var(--wb-text-main);
}

.wb-floating-header-actions {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.wb-floating-body {
  min-height: 0;
  padding: 12px;
  display: grid;
  gap: 10px;
  overflow: auto;
}

.find-window .wb-floating-body {
  gap: 10px;
}

.text-input {
  width: 100%;
  box-sizing: border-box;
  border: 1px solid transparent;
  border-radius: 8px;
  padding: 8px 12px;
  color: var(--wb-text-main);
  background: var(--wb-input-bg);
  transition: background 0.25s cubic-bezier(0.25, 1, 0.5, 1), border-color 0.25s cubic-bezier(0.25, 1, 0.5, 1), box-shadow 0.25s cubic-bezier(0.25, 1, 0.5, 1);
}

.text-input:hover {
  background: var(--wb-input-bg-hover);
}

.text-input:focus {
  background: var(--wb-input-bg-focus);
  border-color: var(--wb-primary);
  outline: none;
  box-shadow: 0 0 0 3px var(--wb-primary-hover);
}

.checkbox-inline {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

.tool-line {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.tool-line.stacked {
  display: grid;
  gap: 6px;
}

.find-flags {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.find-scope-line {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}

.find-summary-text {
  margin-left: auto;
  color: var(--wb-primary-light);
  font-size: 12px;
}

.find-active-hit {
  border: 1px solid var(--wb-primary-light);
  border-radius: 10px;
  padding: 10px 12px;
  display: grid;
  gap: 4px;
  background: var(--wb-primary-soft);
  box-shadow: 0 0 0 2px var(--wb-primary-soft);
}

.find-active-hit strong {
  color: var(--wb-text-main);
  font-size: 12px;
}

.find-active-hit span {
  color: var(--wb-text-muted);
  font-size: 11px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.batch-exclude-note {
  color: var(--wb-text-muted);
  font-size: 11px;
}

.batch-exclude-chips {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.exclude-chip {
  border-radius: 999px;
  padding: 1px 8px;
  font-size: 11px;
  color: var(--wb-text-main);
  background: var(--wb-surface-high, var(--wb-bg-panel));
}

.tool-details {
  border-radius: 8px;
  padding: 6px;
  background: var(--wb-surface-low, var(--wb-bg-panel));
}

.tool-details > summary {
  cursor: pointer;
  color: var(--wb-text-main);
  font-size: 12px;
}

.tool-details[open] > summary {
  margin-bottom: 6px;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 8px 14px;
  background: var(--wb-surface-high, var(--wb-input-bg));
  border: none;
  border-radius: 8px;
  color: var(--wb-text-main);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
  transition: background 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease;
  transform: translateZ(0);
}

.btn:hover:not(:disabled) {
  background: var(--wb-surface-bright, var(--wb-input-bg-hover));
  transform: translateY(-1px);
  box-shadow: var(--wb-shadow-ambient);
}

.btn:active:not(:disabled) {
  transform: translateY(1px) scale(0.97);
  box-shadow: 0 0 0 0 transparent;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

.btn.primary {
  background: var(--wb-primary-container, var(--wb-primary-soft));
  color: var(--wb-primary-light);
}

.btn.primary:hover:not(:disabled) {
  background: var(--wb-gradient-primary, var(--wb-primary));
  color: #fff;
  box-shadow: var(--wb-primary-glow);
}

.btn.danger {
  background: var(--wb-error-container, rgba(225, 29, 72, 0.1));
  color: var(--wb-error, #f43f5e);
}

.btn.danger:hover:not(:disabled) {
  background: #e11d48;
  color: #fff;
  box-shadow: 0 4px 12px rgba(225, 29, 72, 0.2);
}

.btn.mini {
  padding: 4px 10px;
  font-size: 12px;
  border-radius: 6px;
}

@media (max-width: 1100px) {
  .wb-floating-window {
    width: calc(100vw - 16px) !important;
    left: 8px !important;
    right: 8px;
  }
}

@media (max-width: 760px) {
  .wb-floating-window {
    position: absolute;
    left: 8px !important;
    right: 8px !important;
    width: auto !important;
    max-width: none !important;
  }
}
