
.wb-floating-window {
  position: fixed;
  max-width: calc(100vw - 16px);
  max-height: min(74vh, 760px);
  border-radius: 12px;
  background: var(--wb-surface-highest, var(--wb-bg-panel));
  box-shadow: var(--wb-shadow-main);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.wb-floating-header {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: center;
  padding: 12px 16px;
  border-bottom: 1px solid var(--wb-border-subtle);
  background: var(--wb-surface-high, var(--wb-bg-panel));
  cursor: move;
  user-select: none;
  touch-action: none;
}

.wb-floating-header strong {
  font-size: 12px;
  color: var(--wb-text-main);
}

.wb-floating-header-actions {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.wb-floating-body {
  min-height: 0;
  padding: 12px;
  display: grid;
  gap: 10px;
  overflow: auto;
}

.tool-scroll {
  overflow: auto;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.activation-window .tool-scroll {
  max-height: min(58vh, 520px);
}

.activation-item {
  border-radius: 10px;
  padding: 10px 12px;
  display: grid;
  gap: 4px;
  background: var(--wb-surface-low, var(--wb-input-bg));
  transition: background 0.2s ease;
}

.activation-item:hover {
  background: var(--wb-surface-high, var(--wb-input-bg-hover));
}

.activation-main,
.activation-sub {
  display: flex;
  justify-content: space-between;
  gap: 6px;
}

.activation-main strong {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.activation-main span,
.activation-sub {
  color: var(--wb-text-muted);
  font-size: 12px;
}

.activation-sub span:last-child {
  flex: 1;
  text-align: right;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.empty-note {
  color: var(--wb-text-muted);
  font-size: 13px;
  text-align: center;
  letter-spacing: 0.02em;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 8px 14px;
  background: var(--wb-surface-high, var(--wb-input-bg));
  border: none;
  border-radius: 8px;
  color: var(--wb-text-main);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
  transition: background 0.2s ease, box-shadow 0.2s ease, transform 0.2s ease;
  transform: translateZ(0);
}

.btn:hover:not(:disabled) {
  background: var(--wb-surface-bright, var(--wb-input-bg-hover));
  transform: translateY(-1px);
  box-shadow: var(--wb-shadow-ambient);
}

.btn:active:not(:disabled) {
  transform: translateY(1px) scale(0.97);
  box-shadow: 0 0 0 0 transparent;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  transform: none;
  box-shadow: none;
}

.btn.danger {
  background: var(--wb-error-container, rgba(225, 29, 72, 0.1));
  color: var(--wb-error, #f43f5e);
}

.btn.danger:hover:not(:disabled) {
  background: #e11d48;
  color: #fff;
  box-shadow: 0 4px 12px rgba(225, 29, 72, 0.2);
}

.btn.mini {
  padding: 4px 10px;
  font-size: 12px;
  border-radius: 6px;
}

@media (max-width: 1100px) {
  .wb-floating-window {
    width: calc(100vw - 16px) !important;
    left: 8px !important;
    right: 8px;
  }
}

@media (max-width: 760px) {
  .wb-floating-window {
    position: absolute;
    left: 8px !important;
    right: 8px !important;
    width: auto !important;
    max-width: none !important;
  }
}
